{
  "domain_analysis": {
    "business_context": "Order cancellation in a logistics/courier context. A user-initiated cancellation request must respect the physical reality of package fulfillment — once a courier has possession of a package or it is in transit, cancellation has fundamentally different operational meaning than cancelling a newly-placed order. The spec is dangerously vague: it does not define which order states permit cancellation, what 'cancel' means financially, or who qualifies as a 'user'.",
    "bounded_context": "Order Management",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A request by a customer for courier pickup and delivery of a package from origin to destination." },
      { "term": "Order Status", "definition": "The current lifecycle state of an order (e.g., Placed, Confirmed, Assigned, Picked Up, In Transit, Out for Delivery, Delivered, Cancelled)." },
      { "term": "Cancellation", "definition": "A user-initiated request to terminate an order before its completion, triggering state transition to Cancelled and potentially a financial reversal." },
      { "term": "Cancellation Window", "definition": "The set of order statuses during which cancellation is permitted. Determined by whether physical fulfillment has begun." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after operational costs have been incurred (e.g., courier dispatched)." },
      { "term": "Refund", "definition": "Full or partial reversal of payment to the customer upon successful cancellation." },
      { "term": "User", "definition": "The customer who placed the order. Ambiguity: spec does not clarify if admin, sender, or receiver can also cancel." },
      { "term": "Point of No Return", "definition": "The order state beyond which cancellation is no longer possible because physical custody has transferred or delivery is imminent." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order may only be cancelled by the user who placed it (the order owner).",
      "invariant": true,
      "invariant_justification": "Allowing arbitrary actors to cancel orders they do not own is a data integrity and authorization violation. If violated, the system permits unauthorized state mutation.",
      "testable_assertion": "Given user A placed order 123, when user B attempts to cancel order 123, then the system rejects the request with 403 Forbidden."
    },
    {
      "id": "BR-2",
      "rule": "An order can only be cancelled if its current status is within the cancellation window (Placed or Confirmed). Orders that have progressed to Assigned, Picked Up, In Transit, Out for Delivery, or Delivered cannot be cancelled by the user.",
      "invariant": true,
      "invariant_justification": "Physical reality constraint. Once a courier has been dispatched or has custody of a package, user-side cancellation cannot undo the physical action. Violating this creates impossible operational states (cancelled order with a courier still carrying the package).",
      "testable_assertion": "Given an order with status 'In Transit', when the user requests cancellation, then the system rejects the request and returns an error indicating the order is past the cancellation window."
    },
    {
      "id": "BR-3",
      "rule": "A cancelled order's status must transition to 'Cancelled' and this transition is terminal — a cancelled order cannot be reactivated or moved to any other status.",
      "invariant": true,
      "invariant_justification": "State integrity. Cancelled is a terminal state. Allowing resurrection of cancelled orders would corrupt fulfillment pipelines, billing, and reporting.",
      "testable_assertion": "Given an order with status 'Cancelled', when any status transition is attempted, then the system rejects it."
    },
    {
      "id": "BR-4",
      "rule": "When an order in status 'Placed' is cancelled, the customer receives a full refund with no cancellation fee.",
      "invariant": false,
      "invariant_justification": "This is a business policy. A VP could decide to always charge a processing fee. The refund amount and fee structure are policy decisions, not physical constraints.",
      "testable_assertion": "Given an order in status 'Placed' that was prepaid, when the user cancels, then a full refund is issued and no cancellation fee is charged."
    },
    {
      "id": "BR-5",
      "rule": "When an order in status 'Confirmed' is cancelled, the customer receives a refund minus any applicable cancellation fee (if a courier was about to be assigned).",
      "invariant": false,
      "invariant_justification": "Policy decision. The fee amount and conditions under which it applies are configurable business rules.",
      "testable_assertion": "Given an order in status 'Confirmed', when the user cancels, then a refund is issued and any applicable cancellation fee is deducted."
    },
    {
      "id": "BR-6",
      "rule": "Every cancellation must be recorded as an auditable domain event (OrderCancelled) capturing: order ID, user ID, timestamp, order status at time of cancellation, and refund amount.",
      "invariant": true,
      "invariant_justification": "Audit trail integrity. Financial reversals and state changes without audit records make the system unreconcilable. Regulatory and dispute resolution depend on this.",
      "testable_assertion": "Given a successful cancellation, when the event log is queried, then an OrderCancelled event exists with all required fields populated."
    },
    {
      "id": "BR-7",
      "rule": "An order that is already cancelled cannot be cancelled again. The operation must be idempotent — repeated cancellation requests return success but do not create duplicate events or duplicate refunds.",
      "invariant": true,
      "invariant_justification": "Data consistency. Double-cancellation leading to double-refund is a financial integrity violation.",
      "testable_assertion": "Given an order already in status 'Cancelled', when the user requests cancellation again, then the system returns success, no new OrderCancelled event is emitted, and no additional refund is issued."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A user has an order in status 'Placed'",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to 'Cancelled', a full refund is initiated, an OrderCancelled event is emitted, and the user receives confirmation of cancellation"
    },
    {
      "id": "AC-2",
      "given": "A user has an order in status 'Confirmed'",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to 'Cancelled', a refund (minus any applicable cancellation fee) is initiated, an OrderCancelled event is emitted, and the user receives confirmation"
    },
    {
      "id": "AC-3",
      "given": "A user has an order in status 'Picked Up', 'In Transit', 'Out for Delivery', or 'Delivered'",
      "when": "The user requests cancellation",
      "then": "The system rejects the request with a clear error message explaining the order is past the cancellation window and suggesting they contact support"
    },
    {
      "id": "AC-4",
      "given": "A user attempts to cancel an order they did not place",
      "when": "The cancellation request is submitted",
      "then": "The system rejects the request with a 403 Forbidden and does not reveal whether the order exists"
    },
    {
      "id": "AC-5",
      "given": "A user has an order already in status 'Cancelled'",
      "when": "The user requests cancellation again",
      "then": "The system returns a success response, no duplicate refund is issued, and no duplicate event is emitted (idempotent behavior)"
    },
    {
      "id": "AC-6",
      "given": "A user requests cancellation of an order in status 'Placed'",
      "when": "The cancellation is processed but the refund service is temporarily unavailable",
      "then": "The order still transitions to 'Cancelled', the refund is queued for retry, and the user is informed that the refund is being processed"
    },
    {
      "id": "AC-7",
      "given": "A user requests cancellation of an order in status 'Assigned' (courier assigned but has not picked up)",
      "when": "The cancellation request is submitted",
      "then": "The system behavior depends on resolution of escalation ESC-2 below — this state is ambiguous in the spec"
    },
    {
      "id": "AC-8",
      "given": "Two concurrent cancellation requests arrive for the same order",
      "when": "Both are processed",
      "then": "Exactly one cancellation succeeds, exactly one OrderCancelled event is emitted, and exactly one refund is initiated — no race condition produces duplicates"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Order status changes between the user viewing the order and submitting cancellation (e.g., courier is assigned in the interim)",
      "expected_behavior": "Cancellation must check current status at write-time, not at read-time. If the order has moved past the cancellation window, reject the request even if the UI showed it as cancellable."
    },
    {
      "scenario": "User cancels an order that has not yet been charged (e.g., payment authorization pending)",
      "expected_behavior": "Void the authorization rather than issuing a refund. No money should move. The order transitions to Cancelled."
    },
    {
      "scenario": "Cancellation request arrives simultaneously with a status promotion (e.g., courier picks up at the exact moment user cancels)",
      "expected_behavior": "Must be resolved with optimistic locking or version check. Whichever operation commits first wins. If pickup committed first, cancellation is rejected."
    },
    {
      "scenario": "User deletes their account after placing an order but before cancelling",
      "expected_behavior": "Account deletion should not orphan active orders. Either force-cancel open orders during account deletion, or prevent account deletion while orders are active."
    },
    {
      "scenario": "Partial fulfillment — multi-package order where one package is already picked up and another is still in 'Placed'",
      "expected_behavior": "Spec does not address partial cancellation. If multi-package orders exist, the system must either cancel all-or-nothing (and reject if any package is past the window) or support line-item cancellation. Requires clarification (see ESC-3)."
    },
    {
      "scenario": "Refund fails permanently after order is already marked Cancelled",
      "expected_behavior": "The order remains Cancelled (this is correct — the operational state is terminal). The failed refund must trigger an alert to finance/support for manual resolution. The user must be notified that their refund requires manual processing."
    },
    {
      "scenario": "Cancellation of a free/promotional order (zero-cost)",
      "expected_behavior": "Cancellation proceeds normally. No refund is issued (amount is zero). The OrderCancelled event still records refund_amount: 0."
    },
    {
      "scenario": "Bulk cancellation — user attempts to cancel many orders at once via API",
      "expected_behavior": "Each order must be independently validated. Partial success is acceptable (some cancel, some reject). Response must indicate per-order outcome."
    }
  ],

  "business_impact": {
    "financial": "Direct revenue impact — every cancellation is lost revenue. Cancellation fee policy partially offsets sunk operational costs. Incorrect implementation risks double-refunds (money leak) or no-refunds (chargebacks, legal exposure). Refund timing affects cash flow.",
    "operational": "Cancellation after courier assignment wastes dispatch resources. High cancellation rates signal UX or pricing problems upstream. The cancellation window boundary directly determines how much operational waste is absorbed. Support ticket volume will increase if the error messages for rejected cancellations are unclear.",
    "user": "Cancellation is a trust-building feature — users order more confidently when they know they can cancel. Poor cancellation UX (confusing errors, slow refunds, hidden fees) drives churn. Transparent cancellation policies increase customer lifetime value.",
    "risk": "Race conditions between cancellation and fulfillment are the highest technical risk — they can produce impossible states (cancelled order being delivered). Financial risk from double-refund bugs. Compliance risk if audit trail is incomplete. Fraud risk if cancellation policy is too lenient (order-and-cancel abuse).",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Primary beneficiary. Gain ability to self-service cancel, reducing support dependency. Must receive clear feedback on what is cancellable and why." },
      { "group": "Couriers", "impact": "Cancellations after assignment waste courier time and reduce earnings. Cancellation window policy directly affects courier experience and retention." },
      { "group": "Finance/Billing", "impact": "Must reconcile refunds. Need reliable audit events. Double-refund bugs are their nightmare." },
      { "group": "Customer Support", "impact": "Reduced ticket volume for cancellable orders. Increased tickets for orders past the cancellation window if messaging is poor." },
      { "group": "Product/Analytics", "impact": "Cancellation rate is a key business metric. Need clean event data to analyze why users cancel and at which stage." }
    ]
  },

  "confidence": {
    "level": 40,
    "reasoning": "The spec is a single sentence with no definition of cancellation window, order lifecycle states, fee structure, refund policy, multi-package behavior, or who 'user' means beyond the customer. I have applied standard logistics domain knowledge to fill gaps, but multiple critical business decisions remain unspecified. Three escalations are raised, one of which is a potential contradiction (Assigned state ambiguity).",
    "high_confidence_areas": [
      "Terminal state invariant — Cancelled must be final",
      "Authorization — only order owner can cancel",
      "Audit trail requirement for financial operations",
      "Idempotency requirement to prevent double-refunds",
      "Race condition between cancellation and fulfillment must be handled"
    ],
    "low_confidence_areas": [
      "Exact cancellation window — which states are cancellable, especially 'Assigned'",
      "Fee structure and refund policy for each cancellable state",
      "Whether multi-package / partial cancellation is in scope",
      "Whether admin or receiver can also cancel",
      "Refund timing SLA"
    ],
    "assumptions": [
      "Order lifecycle includes at minimum: Placed → Confirmed → Assigned → Picked Up → In Transit → Out for Delivery → Delivered",
      "Only the customer who placed the order can cancel (not admin, not receiver)",
      "Cancellation window closes at or before 'Assigned' — physical fulfillment beginning is the boundary",
      "Payment is collected at order placement (prepaid model), so cancellation triggers a refund rather than simply voiding a future charge",
      "The system is a single-package-per-order model unless clarified otherwise"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order states permit cancellation. The critical question is whether 'Assigned' (courier dispatched but has not picked up the package) is within the cancellation window. This is the most operationally significant boundary — allowing cancellation at 'Assigned' wastes courier dispatch time; disallowing it frustrates users who see no physical action yet.",
      "affected_stakeholders": ["Customers", "Couriers", "Product"],
      "options": [
        "A: Cancellation window is Placed and Confirmed only (conservative — protects courier operations)",
        "B: Cancellation window includes Assigned, with a cancellation fee to offset courier dispatch cost",
        "C: Cancellation window includes Assigned, courier is notified and reassigned, no fee"
      ],
      "recommendation": "Option B — it balances user flexibility with operational cost recovery. Most logistics platforms allow cancellation until physical pickup, with a fee after dispatch."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'users' but does not clarify if this means only the customer who placed the order, or also includes admins, receivers, or third-party senders. Admin cancellation typically has a wider window and different business rules.",
      "affected_stakeholders": ["Customers", "Customer Support", "Product"],
      "options": [
        "A: Only the placing customer can cancel via this feature; admin cancellation is a separate feature",
        "B: Both customer and admin can cancel, with admin having an extended cancellation window"
      ],
      "recommendation": "Option A — scope this feature to customer self-service cancellation only. Admin cancellation has different rules and should be a separate feature."
    },
    {
      "type": "missing_context",
      "description": "No mention of multi-package orders or partial cancellation. If the order model supports multiple packages/line-items, the cancellation semantics are fundamentally different (all-or-nothing vs. per-item).",
      "affected_stakeholders": ["Customers", "Finance/Billing", "Product"],
      "options": [
        "A: Assume single-package orders only for this feature",
        "B: Support partial cancellation for multi-package orders",
        "C: All-or-nothing cancellation even for multi-package orders"
      ],
      "recommendation": "Option A — confirm with PM whether multi-package orders exist in the domain. If not, this is moot. If yes, defer partial cancellation to a follow-up feature."
    }
  ],

  "rejection_reasons": []
}

